function includesAny(text, arr) {
  return arr.some(k => text.includes(k));
}

return items.map((item) => {
  const j = item.json || {};
  const warnings = [...(j.warnings || [])];

  const userText = (j.user_text_norm || "").toLowerCase();
  const labelText = (j.label_text_norm || "").toLowerCase();
  const image = j.image_analysis || {};

  const labelLooksReal =
    labelText.length >= 40 ||
    /por\s*100\s*g|porci[oÃ³]n|energ[iÃ­]a|kcal|prote[iÃ­]nas|carbohidratos|grasas|sodio/.test(labelText);

  const packagedKeywords = [
    "tabla nutricional", "por 100", "porciÃ³n", "porcion", "kcal", "proteinas", "carbohidratos", "grasas",
    "yogurt", "galletas", "barra", "cereal", "snack", "gatorade", "bebible", "light", "pack", "paquete",
    "lata", "botella", "envase", "etiqueta"
  ];

  const imageHintsPackaged =
    image?.packaging_detected === true ||
    (typeof image?.type === "string" && image.type.toLowerCase().includes("label"));

  const packaged_product = labelLooksReal || includesAny(userText, packagedKeywords) || imageHintsPackaged;

  // Â¿falta lo mÃ­nimo para calcular?
  const hasGramsHint = /\b(\d+)\s*(g|gr|gramos|ml|mililitros)\b/.test(userText) || /\b(\d+)\s*(g|gr|gramos|ml)\b/.test(labelText);
  const needs_label = packaged_product && !labelLooksReal;
  const needs_grams = packaged_product && !hasGramsHint;

  const clarifying_questions = [];
  if (packaged_product) {
    if (needs_label) {
      clarifying_questions.push("Â¿Me mandÃ¡s foto del frente del producto y otra de la tabla nutricional?");
    }
    if (needs_grams) {
      clarifying_questions.push("Â¿CuÃ¡nta cantidad consumiste? (gramos o ml, o si fue 1 unidad indicame tamaÃ±o/peso)");
    }
  }

  // Si detectÃ³ packaged pero no tiene nada Ãºtil, avisar
  if (packaged_product && needs_label && needs_grams) {
    warnings.push("Producto envasado detectado, pero faltan tabla nutricional y cantidad consumida.");
  }

  return {
    json: {
      ...j,
      packaged_product,
      packaged_needs_label: needs_label,
      packaged_needs_grams: needs_grams,
      packaged_clarifying_questions: clarifying_questions,
      warnings
    }
  };
});

// n8n Code node (JavaScript) â€” format_response (robusto post ai_analysis)
// Objetivo: SIEMPRE devolver campos consistentes y "reply_text" listo para workflow main.

function normalizeNewlines(s) {
  return (s ?? "").toString().replace(/\r\n/g, "\n").replace(/\r/g, "\n");
}

function stripDiacritics(s) {
  return (s ?? "")
    .toString()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function toSnakeKey(s) {
  return stripDiacritics(s)
    .toLowerCase()
    .trim()
    .replace(/[Â¿?]/g, "")
    .replace(/[()]/g, "")
    .replace(/[^\w\s-]/g, "")
    .replace(/[\s-]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function safeTrim(s) {
  return (s ?? "").toString().trim();
}

function isPlaceholder(s) {
  const v = safeTrim(s).toUpperCase();
  return !v || v === "N/A" || v === "NA" || v === "NULL" || v === "UNDEFINED";
}

function coerceNumberLike(v) {
  const raw = safeTrim(v);
  if (!raw) return { ok: false, value: v };
  const cleaned = raw
    .replace(/\s/g, "")
    .replace(/(\d)\.(\d{3})(\D|$)/g, "$1$2$3") // miles con punto
    .replace(/(\d),(?=\d{3}(\D|$))/g, "$1")   // miles con coma
    .replace(",", ".");                      // decimal coma -> punto

  if (!/^-?\d+(\.\d+)?$/.test(cleaned)) return { ok: false, value: v };
  const num = Number(cleaned);
  if (!Number.isFinite(num)) return { ok: false, value: v };
  return { ok: true, value: num };
}

function coerceBool(valueStr) {
  const v = safeTrim(valueStr).toLowerCase();
  if (!v) return { value: valueStr };

  if (v === "true") return { value: true };
  if (v === "false") return { value: false };

  if (v === "si" || v === "sÃ­") return { value: true };
  if (v === "no") return { value: false };

  return { value: valueStr };
}

function stripCodeFences(text) {
  const t = normalizeNewlines(text).trim();
  const m = t.match(/^```(?:json)?\s*\n([\s\S]*?)\n```$/i);
  if (m) return m[1].trim();
  return t;
}

/**
 * Extrae texto del output tÃ­pico (OpenAI / LLM chain / etc.)
 */
function extractAnalyzerText(input) {
  const candidates = [
    input?.output?.[0]?.content?.[0]?.text,
    input?.output?.[0]?.text,
    input?.content?.[0]?.text,
    input?.text,
    input?.message,
  ];

  for (const c of candidates) {
    if (typeof c === "string" && c.trim()) return c;
  }

  if (Array.isArray(input?.output)) {
    for (const out of input.output) {
      const t = out?.content?.[0]?.text;
      if (typeof t === "string" && t.trim()) return t;
    }
  }

  return "";
}

/**
 * Extrae primer JSON substring (obj/array) desde texto con basura alrededor.
 * Balanceo bÃ¡sico respetando strings.
 */
function extractFirstJsonSubstring(raw) {
  const s = stripCodeFences(raw);
  if (!s) return null;

  const starts = [];
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (c === "{" || c === "[") starts.push(i);
  }
  if (!starts.length) return null;

  const tryFrom = (startIdx) => {
    const open = s[startIdx];
    const close = open === "{" ? "}" : "]";
    let depth = 0;
    let inStr = false;
    let esc = false;

    for (let i = startIdx; i < s.length; i++) {
      const ch = s[i];

      if (inStr) {
        if (esc) esc = false;
        else if (ch === "\\") esc = true;
        else if (ch === "\"") inStr = false;
        continue;
      }

      if (ch === "\"") {
        inStr = true;
        continue;
      }

      if (ch === open) depth++;
      if (ch === close) depth--;

      if (depth === 0) return s.slice(startIdx, i + 1).trim();
    }
    return null;
  };

  for (const idx of starts) {
    const candidate = tryFrom(idx);
    if (!candidate) continue;
    if (
      (candidate.startsWith("{") && candidate.endsWith("}")) ||
      (candidate.startsWith("[") && candidate.endsWith("]"))
    ) return candidate;
  }
  return null;
}

function tryParseJsonLoose(text) {
  const t = stripCodeFences(text).trim();
  if (!t) return { ok: false, value: null };

  const looksJson = (t.startsWith("{") && t.endsWith("}")) || (t.startsWith("[") && t.endsWith("]"));
  if (looksJson) {
    try { return { ok: true, value: JSON.parse(t) }; } catch (_) {}
  }

  const sub = extractFirstJsonSubstring(t);
  if (sub) {
    try { return { ok: true, value: JSON.parse(sub) }; } catch (_) {}
  }

  return { ok: false, value: null };
}

/**
 * Split de secciones robusto:
 * Soporta:
 * - "1) TITULO: ..." (con valor inline o body abajo)
 * - "TITULO_EN_MAYUS: ..." (con valor inline o body abajo)
 */
function splitSections(fullText) {
  const text = normalizeNewlines(fullText).trim();
  if (!text) return [{ title: "RAW", body: "" }];

  const lines = text.split("\n");
  const headers = [];

  const isUpperHeader = (line) => {
    // evita "Hola:" / frases normales:
    // requiere mayormente MAYÃšSCULA / _ / nÃºmeros / separadores
    // y un mÃ­nimo de longitud Ãºtil.
    return /^([A-ZÃÃ‰ÃÃ“ÃšÃœÃ‘0-9_][A-ZÃÃ‰ÃÃ“ÃšÃœÃ‘0-9_ \-/]{2,80})\s*:\s*(.*)$/.test(line);
  };

  for (let i = 0; i < lines.length; i++) {
    const raw = lines[i];
    const line = raw.trim();
    if (!line) continue;

    // 1) Numerado: "1) TITULO: resto?"
    let m = line.match(/^(\d+)\)\s*([^\n:]{2,80})\s*:\s*(.*)$/);
    if (m) {
      headers.push({
        lineIndex: i,
        title: m[2].trim(),
        inline: m[3] ?? "",
        kind: "numbered",
      });
      continue;
    }

    // 2) MayÃºscula (o estilo KEY): "ROMMY_STATUS: resto?"
    m = line.match(/^([A-ZÃÃ‰ÃÃ“ÃšÃœÃ‘0-9_][A-ZÃÃ‰ÃÃ“ÃšÃœÃ‘0-9_ \-/]{2,80})\s*:\s*(.*)$/);
    if (m && isUpperHeader(line)) {
      headers.push({
        lineIndex: i,
        title: m[1].trim(),
        inline: m[2] ?? "",
        kind: "plain",
      });
      continue;
    }
  }

  if (!headers.length) return [{ title: "RAW", body: text }];

  const sections = [];
  for (let h = 0; h < headers.length; h++) {
    const cur = headers[h];
    const next = headers[h + 1];

    const bodyStartLine = cur.lineIndex + 1;
    const bodyEndLine = next ? next.lineIndex : lines.length;

    const bodyLines = [];

    // si el header vino con "inline value", lo agregamos como primera lÃ­nea del body
    if (safeTrim(cur.inline)) bodyLines.push(cur.inline);

    // sumamos lÃ­neas siguientes hasta el prÃ³ximo header
    const rest = lines.slice(bodyStartLine, bodyEndLine);
    const restJoined = rest.join("\n").trim();
    if (restJoined) bodyLines.push(restJoined);

    sections.push({ title: cur.title, body: bodyLines.join("\n").trim() });
  }

  return sections.length ? sections : [{ title: "RAW", body: text }];
}

function parseQuestionsFlexible(sectionBody) {
  const t = normalizeNewlines(sectionBody).trim();
  if (!t) return [];

  // Caso 1: ya viene con saltos de lÃ­nea/bullets
  const lines = t.split("\n").map(x => x.trim()).filter(Boolean);
  const hasLineStyle = lines.length > 1 || lines.some(l => l.startsWith("-") || /^\d+\)/.test(l));
  if (hasLineStyle) {
    const questions = [];
    for (const line of lines) {
      const bullet = line.match(/^\-\s*(.+)$/);
      const content = bullet ? bullet[1].trim() : line;
      const q = content.replace(/^\d+\)\s*/, "").trim();
      if (q) questions.push(q);
    }
    return questions;
  }

  // Caso 2: todo en una lÃ­nea: "1) ... 2) ... 3) ..."
  const one = t.replace(/\s+/g, " ").trim();
  const matches = [];
  const re = /(?:^|\s)(\d+)\)\s*([\s\S]*?)(?=(?:\s\d+\)\s)|$)/g;
  let m;
  while ((m = re.exec(one)) !== null) {
    const q = safeTrim(m[2]).replace(/\s*;\s*$/, "").trim();
    if (q) matches.push(q);
  }
  if (matches.length) return matches;

  // Caso 3: separados por ";"
  const parts = one.split(";").map(x => x.trim()).filter(Boolean);
  if (parts.length > 1) return parts;

  return one ? [one] : [];
}

function parseFlagsFlexible(sectionBody) {
  const t = normalizeNewlines(sectionBody).trim();
  const out = { list: [], kv: {} };
  if (!t) return out;

  const cleaned = t
    .replace(/^\-\s*/gm, "")
    .replace(/\s+/g, " ")
    .trim();

  const parts = cleaned
    .split(/;|\n|\|/g)
    .map(p => p.trim())
    .filter(Boolean);

  for (const p of parts) {
    // soporta "a=b" y "A" simples
    const eq = p.match(/^([^=]{1,80})=(.+)$/);
    if (eq) {
      const k = toSnakeKey(eq[1]);
      const vRaw = eq[2].trim();

      // bool/number/string
      const b = coerceBool(vRaw);
      let v = b.value;
      const n = coerceNumberLike(vRaw);
      if (n.ok) v = n.value;

      out.kv[k] = v;
      out.list.push(`${k}=${typeof v === "string" ? v : String(v)}`);
    } else {
      out.list.push(p);
    }
  }

  // uniq list
  out.list = [...new Set(out.list)];
  return out;
}

function parseSingleValue(sectionBody) {
  const t = normalizeNewlines(sectionBody).trim();
  if (!t) return null;
  const one = t.split("\n").map(x => x.trim()).filter(Boolean);
  if (one.length === 1) return one[0];
  return t;
}

function pickFirst(obj, keys) {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return null;
}

function extractSectionFallback(rawText, keyName) {
  // captura header con inline o multiline hasta el prÃ³ximo header MAYÃšSCULA o fin.
  const t = normalizeNewlines(rawText);
  const keyEsc = keyName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const re = new RegExp(
    `${keyEsc}\\s*:\\s*([\\s\\S]*?)(?=\\n[A-ZÃÃ‰ÃÃ“ÃšÃœÃ‘0-9_][A-ZÃÃ‰ÃÃ“ÃšÃœÃ‘0-9_ \\-/]{2,80}\\s*:\\s*|$)`,
    "g"
  );
  const m = re.exec(t);
  return m ? safeTrim(m[1]) : "";
}

function deriveStopAndStatus(statusText, actionText, replyText) {
  const s = safeTrim(statusText).toUpperCase();
  const a = safeTrim(actionText).toUpperCase();

  const stop =
    ["NEEDS_CLARIFICATION", "ERROR", "FAIL", "FAILED"].includes(s) ||
    ["ASK_MORE_INFO", "ESCALATE_TO_HUMAN", "ERROR", "STOP"].includes(a);

  const status =
    stop ? (s || "NEEDS_CLARIFICATION")
         : (s || "OK");

  // success: si tengo replyText utilizable (aunque sea error/clarification)
  const success = !isPlaceholder(replyText);

  return { stop, status, success };
}

return items.map((item) => {
  const input = item.json || {};
  const warnings = [];

  // 1) Extraer texto bruto de ai_analysis
  let rawText = extractAnalyzerText(input);
  rawText = stripCodeFences(rawText);

  if (isPlaceholder(rawText)) {
    warnings.push("ai_analysis devolviÃ³ texto vacÃ­o/placeholder (N/A).");
  }

  // 2) Si vino JSON, intentamos mapear o extraer 'response_text'
  const jsonTry = tryParseJsonLoose(rawText);
  let textForParsing = rawText;
  let directObj = null;

  if (jsonTry.ok) {
    const parsed = jsonTry.value;

    // si es objeto con campos finales (o response_text)
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      const maybeResponseText =
        parsed.response_text ?? parsed.responseText ?? parsed.text ?? parsed.output_text ?? parsed.message ?? null;

      if (typeof maybeResponseText === "string" && safeTrim(maybeResponseText)) {
        textForParsing = maybeResponseText;
      } else {
        directObj = parsed;
      }
    }

    // si es array, intentar primer objeto
    if (Array.isArray(parsed) && parsed.length) {
      const firstObj = parsed.find(x => x && typeof x === "object") || null;
      if (firstObj?.response_text) textForParsing = firstObj.response_text;
      else if (firstObj && !directObj) directObj = firstObj;
    }
  }

  // 3) Armar salida base (siempre consistente)
  const out = {
    // passthrough IDs si estuvieran
    phone: pickFirst(input, ["phone"]),
    patient_dni: pickFirst(input, ["patient_dni"]),
    patient_key: pickFirst(input, ["patient_key"]),
    timezone: pickFirst(input, ["timezone"]),
    context_date: pickFirst(input, ["context_date"]),
    conversation_id: pickFirst(input, ["conversation_id"]),
    message_id: pickFirst(input, ["message_id"]),

    // campos textuales â€œpara el workflow mainâ€
    final_reply_text: "",
    reply_text: "",
    rommy_status_text: "",
    accion_recomendada_text: "",
    resumen_para_rommy_text: "",
    datos_para_tracker_text: "",
    preguntas_pendientes: [],
    flags_list: [],
    flags_kv: {},

    // routing
    stop: false,
    status: "UNKNOWN",
    success: false,

    // debug
    raw_text: textForParsing,
    raw_sections: {},
    warnings,
    // opcional: objeto directo si el modelo devolviÃ³ JSON estructurado
    raw_llm_json: directObj,
  };

  // 4) Si el modelo devolviÃ³ JSON ya â€œfinalâ€, mergeamos y salimos (pero igual garantizamos los *_text)
  if (directObj && typeof directObj === "object") {
    Object.assign(out, directObj);

    // normalizaciÃ³n de campos textuales si vienen con otros nombres
    out.rommy_status_text = safeTrim(
      out.rommy_status_text || out.rommy_status || out.status_text || out.status
    );

    out.accion_recomendada_text = safeTrim(
      out.accion_recomendada_text || out.accion_recomendada || out.action || out.accion
    );

    out.final_reply_text = safeTrim(
      out.final_reply_text || out.reply_text || out.mensaje_listo_para_paciente || out.message_to_patient || ""
    );
    out.reply_text = out.final_reply_text;

    out.resumen_para_rommy_text = safeTrim(
      out.resumen_para_rommy_text || out.resumen_para_rommy || out.summary_for_rommy || ""
    );

    out.datos_para_tracker_text = safeTrim(
      out.datos_para_tracker_text || out.datos_para_tracker || out.tracker_text || ""
    );

    // preguntas
    if (!Array.isArray(out.preguntas_pendientes)) {
      out.preguntas_pendientes = parseQuestionsFlexible(out.preguntas_pendientes ?? "");
    }

    // flags
    if (!out.flags_kv || typeof out.flags_kv !== "object") out.flags_kv = {};
    if (!Array.isArray(out.flags_list)) out.flags_list = [];

    const { stop, status, success } = deriveStopAndStatus(
      out.rommy_status_text,
      out.accion_recomendada_text,
      out.reply_text
    );
    out.stop = stop;
    out.status = status;
    out.success = success;

    if (!out.reply_text) out.reply_text = "";
    if (!out.final_reply_text) out.final_reply_text = out.reply_text;

    return { json: out };
  }

  // 5) Parsear texto con secciones (inline o multiline)
  if (isPlaceholder(textForParsing)) {
    warnings.push("No se encontrÃ³ texto utilizable para parsear (textForParsing vacÃ­o/placeholder).");
    textForParsing = rawText || "";
  }

  const sections = splitSections(textForParsing);

  for (const sec of sections) {
    const titleNorm = toSnakeKey(sec.title);
    out.raw_sections[titleNorm] = sec.body;

    if (titleNorm === "rommy_status") {
      out.rommy_status_text = safeTrim(parseSingleValue(sec.body) || "");
    } else if (titleNorm === "mensaje_listo_para_paciente") {
      out.reply_text = safeTrim(sec.body);
    } else if (titleNorm === "resumen_para_rommy") {
      out.resumen_para_rommy_text = safeTrim(sec.body);
    } else if (titleNorm === "datos_para_tracker") {
      out.datos_para_tracker_text = safeTrim(sec.body);
    } else if (titleNorm === "accion_recomendada") {
      out.accion_recomendada_text = safeTrim(parseSingleValue(sec.body) || "");
    } else if (titleNorm === "preguntas_pendientes_si_aplica" || titleNorm === "preguntas_pendientes") {
      out.preguntas_pendientes = parseQuestionsFlexible(sec.body);
    } else if (titleNorm === "flags") {
      const f = parseFlagsFlexible(sec.body);
      out.flags_list = f.list;
      out.flags_kv = f.kv;
    }
  }

  // 6) Fallbacks ultra importantes (por si el split fallÃ³ o vino raro)
  if (!out.rommy_status_text) {
    out.rommy_status_text = safeTrim(extractSectionFallback(textForParsing, "ROMMY_STATUS"));
  }
  if (!out.reply_text) {
    out.reply_text = safeTrim(extractSectionFallback(textForParsing, "MENSAJE_LISTO_PARA_PACIENTE"));
  }
  if (!out.resumen_para_rommy_text) {
    out.resumen_para_rommy_text = safeTrim(extractSectionFallback(textForParsing, "RESUMEN_PARA_ROMMY"));
  }
  if (!out.datos_para_tracker_text) {
    out.datos_para_tracker_text = safeTrim(extractSectionFallback(textForParsing, "DATOS_PARA_TRACKER"));
  }
  if (!out.accion_recomendada_text) {
    out.accion_recomendada_text = safeTrim(extractSectionFallback(textForParsing, "ACCION_RECOMENDADA"));
  }
  if (!out.preguntas_pendientes?.length) {
    const qFallback = extractSectionFallback(textForParsing, "PREGUNTAS_PENDIENTES");
    out.preguntas_pendientes = parseQuestionsFlexible(qFallback);
  }
  if ((!out.flags_list?.length) && Object.keys(out.flags_kv || {}).length === 0) {
    const flagsFallback = extractSectionFallback(textForParsing, "FLAGS");
    const f = parseFlagsFlexible(flagsFallback);
    out.flags_list = f.list;
    out.flags_kv = f.kv;
  }

  // 7) Normalizaciones finales
  out.rommy_status_text = safeTrim(out.rommy_status_text);
  out.accion_recomendada_text = safeTrim(out.accion_recomendada_text);

  // reply final
  out.final_reply_text = safeTrim(out.reply_text);

  // si sigue vacÃ­o, NO devolvemos N/A: generamos fallback explÃ­cito
  if (isPlaceholder(out.final_reply_text)) {
    // si hay preguntas, armamos mensaje con preguntas; si no, mensaje genÃ©rico
    if (Array.isArray(out.preguntas_pendientes) && out.preguntas_pendientes.length) {
