/**
 * normalize_inputs (ULTRA robusto 99.9% - parser multi-estrategia)
 * FIX definitivo: decodifica plan_json aunque venga:
 * - objeto
 * - string JSON vÃ¡lido
 * - string con JSON embebido
 * - string escapado: {\"status\":\"PARTIAL\"...}
 * - string doble-escapado (backslashes duplicados)
 * - con caracteres de control invisibles (PDF / WhatsApp / iLovePDF)
 */

function normalizeText(s) {
  return (s ?? "").toString().replace(/\s+/g, " ").trim();
}

function stripDiacritics(s) {
  return (s ?? "")
    .toString()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function normKey(s) {
  return stripDiacritics(s)
    .toLowerCase()
    .replace(/_/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

/**
 * Quita NUL/BOM y control chars peligrosos.
 * OJO: NO elimina \n \r \t porque son whitespace vÃ¡lido fuera de strings,
 * pero sÃ­ elimina el resto de control chars ASCII.
 */
function sanitizeBase(s) {
  return (s ?? "")
    .toString()
    .replace(/^\uFEFF/, "") // BOM
    .replace(/\u0000/g, "") // NUL
    .replace(/[\u0001-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, "") // control chars (except \t \n \r)
    .replace(/\r\n/g, "\n")
    .trim();
}

/**
 * Escapa caracteres de control SOLO dentro de strings JSON.
 * Esto salva casos donde el texto trae U+2028/U+2029 o tabs/newlines reales dentro de strings.
 */
function escapeControlCharsInsideJsonStrings(jsonText) {
  const s = sanitizeBase(jsonText);
  if (!s) return s;

  let out = "";
  let inStr = false;
  let esc = false;

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    const code = ch.charCodeAt(0);

    if (!inStr) {
      if (ch === "\"") inStr = true;
      out += ch;
      continue;
    }

    // inStr === true
    if (esc) {
      esc = false;
      out += ch;
      continue;
    }

    if (ch === "\\") {
      esc = true;
      out += ch;
      continue;
    }

    if (ch === "\"") {
      inStr = false;
      out += ch;
      continue;
    }

    // dentro de strings: escapamos control chars reales
    if (ch === "\n") { out += "\\n"; continue; }
    if (ch === "\r") { out += "\\r"; continue; }
    if (ch === "\t") { out += "\\t"; continue; }

    // U+2028 / U+2029 (muy comunes en PDFs)
    if (code === 0x2028) { out += "\\u2028"; continue; }
    if (code === 0x2029) { out += "\\u2029"; continue; }

    // cualquier otro control < 0x20
    if (code < 0x20) {
      out += "\\u" + code.toString(16).padStart(4, "0");
      continue;
    }

    out += ch;
  }

  return out;
}

/**
 * Extrae el primer JSON (objeto/array) embebido en texto (balanceo respetando strings).
 */
function extractFirstJsonSubstring(raw) {
  const s = sanitizeBase(raw);
  if (!s) return null;

  const starts = [];
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (c === "{" || c === "[") starts.push(i);
  }
  if (!starts.length) return null;

  const tryFrom = (startIdx) => {
    const open = s[startIdx];
    const close = open === "{" ? "}" : "]";
    let depth = 0;
    let inStr = false;
    let esc = false;

    for (let i = startIdx; i < s.length; i++) {
      const ch = s[i];

      if (inStr) {
        if (esc) esc = false;
        else if (ch === "\\") esc = true;
        else if (ch === "\"") inStr = false;
        continue;
      }

      if (ch === "\"") { inStr = true; continue; }

      if (ch === open) depth++;
      if (ch === close) depth--;

      if (depth === 0) return s.slice(startIdx, i + 1).trim();
    }
    return null;
  };

  for (const idx of starts) {
    const cand = tryFrom(idx);
    if (!cand) continue;
    if (
      (cand.startsWith("{") && cand.endsWith("}")) ||
      (cand.startsWith("[") && cand.endsWith("]"))
    ) return cand;
  }

  return null;
}

/**
 * Detecta JSON escapado â€œa lo brutoâ€: {\"k\":\"v\"...}
 */
function looksLikeEscapedJson(raw) {
  const s = sanitizeBase(raw);
  if (!s) return false;
  return s.startsWith("{\\\"") || s.startsWith("[\\\"") || /\\\"[A-Za-z0-9_\-\s]+\\\"\s*:/.test(s);
}

/**
 * Remueve TODOS los backslashes inmediatamente antes de comillas:
 * - \"   -> "
 * - \\\" -> "
 * - \\\\\" -> "
 */
function unescapeOnlyQuotesAggressive(raw) {
  const s = sanitizeBase(raw);
  if (!s) return s;
  // uno o mÃ¡s "\" antes de una comilla
  return s.replace(/\\+"/g, "\"").replace(/\\\//g, "/").trim();
}

/**
 * Intenta parsear; si devuelve string que parece JSON, re-parsea hasta 3 veces.
 */
function tryParseJsonWithReparse(str) {
  const s = escapeControlCharsInsideJsonStrings(str);
  try {
    let v = JSON.parse(s);

    for (let i = 0; i < 3; i++) {
      if (typeof v === "string") {
        const t = sanitizeBase(v);
        if (t.startsWith("{") || t.startsWith("[") || looksLikeEscapedJson(t)) {
          // reintento
          try { v = JSON.parse(escapeControlCharsInsideJsonStrings(t)); continue; } catch (_) { break; }
        }
      }
      break;
    }

    return { ok: true, value: v };
  } catch (e) {
    return { ok: false, error: e };
  }
}

/**
 * Decodificador por â€œenvolver como string JSONâ€ (sirve para doble-escapes).
 * Importante: despuÃ©s de decodificar, escapamos control chars dentro de strings y reciÃ©n ahÃ­ parseamos.
 */
function decodeEscapesViaJsonString(raw) {
  const s = sanitizeBase(raw);
  if (!s) return null;

  // construimos un JSON string literal seguro:
  //  - duplicamos backslashes
  //  - escapamos comillas
  const quoted = '"' + s.replace(/\\/g, "\\\\").replace(/"/g, '\\"') + '"';

  try {
    const decoded = JSON.parse(quoted); // devuelve string â€œdecodificadaâ€
    return decoded;
  } catch (_) {
    return null;
  }
}

/**
 * Parser principal: prueba varias rutas hasta encontrar objeto/array.
 */
function safeParseJson(maybeValue, fallback = null) {
  if (maybeValue == null) return fallback;
  if (typeof maybeValue === "object") return maybeValue;
  if (typeof maybeValue !== "string") return fallback;

  const raw0 = sanitizeBase(maybeValue);
  if (!raw0) return fallback;

  // 1) parse directo
  let r = tryParseJsonWithReparse(raw0);
  if (r.ok) return r.value;

  // 2) JSON embebido
  const emb0 = extractFirstJsonSubstring(raw0);
  if (emb0) {
    r = tryParseJsonWithReparse(emb0);
    if (r.ok) return r.value;
  }

  // 3) escapado tipo {\"...\"} (o peor)
  if (looksLikeEscapedJson(raw0)) {
    const unq = unescapeOnlyQuotesAggressive(raw0);
    r = tryParseJsonWithReparse(unq);
    if (r.ok) return r.value;

    const emb1 = extractFirstJsonSubstring(unq);
    if (emb1) {
      r = tryParseJsonWithReparse(emb1);
      if (r.ok) return r.value;
    }
  }

  // 4) decoder por JSON-string (maneja doble-escapes y variantes)
  const decoded = decodeEscapesViaJsonString(raw0);
  if (decoded) {
    r = tryParseJsonWithReparse(decoded);
    if (r.ok) return r.value;

    const emb2 = extractFirstJsonSubstring(decoded);
    if (emb2) {
      r = tryParseJsonWithReparse(emb2);
      if (r.ok) return r.value;
    }

    // si decoded todavÃ­a parece escapado, intentamos quotes-aggressive
    if (looksLikeEscapedJson(decoded)) {
      const unq2 = unescapeOnlyQuotesAggressive(decoded);
      r = tryParseJsonWithReparse(unq2);
      if (r.ok) return r.value;
    }
  }

  return fallback;
}

function looksLikePlan(p) {
  if (!p || typeof p !== "object" || Array.isArray(p)) return false;
  return Boolean(
    p.status ||
    p.plan_status ||
    p.patient ||
    p.targets ||
    p.schedule ||
    p.plan_meta ||
    p.extras ||
    p.constraints ||
    p.recommendations
  );
}

function unwrapPlanObject(planObj, warnings, depth = 0) {
  if (depth > 12) return planObj;

  let p = planObj;

  if (Array.isArray(p)) {
    if (p.length === 1) return unwrapPlanObject(p[0], warnings, depth + 1);
    const firstObj = p.find((x) => x && typeof x === "object") || null;
    if (firstObj) return unwrapPlanObject(firstObj, warnings, depth + 1);
    return p;
  }

  if (p && typeof p === "object") {
    if (looksLikePlan(p)) return p;

    for (const k of ["plan", "data", "result", "output", "payload"]) {
      if (p[k] && typeof p[k] === "object") {
        const inner = p[k];
        if (looksLikePlan(inner) || Array.isArray(inner)) {
          return unwrapPlanObject(inner, warnings, depth + 1);
        }
      }
    }

    const maybeStr =
      p.nutrition_plan ??
      p.plan_json ??
      p.plan_json_raw ??
      p.current_plan ??
      p.plan_raw ??
      null;

    if (typeof maybeStr === "string" && maybeStr.trim()) {
      const inner = safeParseJson(maybeStr, null);
      if (inner) return unwrapPlanObject(inner, warnings, depth + 1);
      warnings.push("No se pudo parsear plan embebido dentro del wrapper.");
    }
  }

  return p;
}

function detectMealFromText(userText) {
  const t = normKey(userText);
  if (/(desayun|desay\b)/.test(t)) return "desayuno";
  if (/(media\s*manana|media\s*maÃ±ana|colacion|colaci[oÃ³]n)/.test(t)) return "media_manana";
  if (/(almuer|almorz|almorc)/.test(t)) return "almuerzo";
  if (/(media\s*tarde|meriend|once\b)/.test(t)) return "media_tarde";
  if (/(cen[eÃ©]|\bcena\b)/.test(t)) return "cena";
  return "unknown";
}

function mapDetectedMealToPlanMealKey(detectedMeal) {
  if (detectedMeal === "media_manana") return "media maÃ±ana";
  if (detectedMeal === "media_tarde") return "media tarde";
  return detectedMeal;
}

function pickMealSection(planObj, detectedMeal) {
  const schedule = planObj?.schedule || planObj?.plan?.schedule;
  if (!schedule) return null;

  const weekday = Array.isArray(schedule.weekday) ? schedule.weekday : [];
  const weekend = Array.isArray(schedule.weekend) ? schedule.weekend : [];

  const keyNorm = normKey(mapDetectedMealToPlanMealKey(detectedMeal));

  const findIn = (arr) => {
    if (!Array.isArray(arr)) return null;

    let meal = arr.find((x) => normKey(x?.meal_name) === keyNorm);
    if (meal) return meal;

    if (detectedMeal !== "unknown") {
      meal = arr.find((x) => normKey(x?.meal_name).includes(keyNorm));
      if (meal) return meal;
    }

    const alt = detectedMeal.replace("_", " ");
    meal = arr.find((x) => normKey(x?.meal_name).includes(normKey(alt)));
    return meal || null;
  };

  return findIn(weekday) || findIn(weekend) || null;
}

function computePlanStatus(planObj) {
  if (!planObj || typeof planObj !== "object") return null;

  const raw =
    planObj?.plan_status ??
    planObj?.plan?.plan_status ??
    planObj?.status ??
    planObj?.plan?.status ??
    null;

  if (raw == null) return looksLikePlan(planObj) ? "sent" : null;

  if (typeof raw === "object") {
    const candidate = raw.estado ?? raw.status ?? raw.value ?? raw.result ?? null;
    if (candidate != null) return computePlanStatus({ status: candidate });
    return looksLikePlan(planObj) ? "sent" : null;
  }

  if (typeof raw === "boolean") return raw ? "sent" : "not_found";

  const up = String(raw).trim().toUpperCase();

  if (["OK", "SENT", "FOUND", "SUCCESS", "TRUE"].includes(up)) return "sent";
  if (["PARTIAL", "INCOMPLETE"].includes(up)) return "partial";
  if (["NOT_FOUND", "MISSING", "NONE", "NO_PLAN"].includes(up)) return "not_found";
  if (["ERROR", "FAIL", "FAILED"].includes(up)) return "error";

  return up.toLowerCase();
}

function buildPlanContext(planObj, mealSection, plan_status) {
  if (!planObj) return null;

  const targets = planObj.targets || planObj.plan?.targets || null;

  return {
    plan_status,
    patient: planObj.patient || planObj.plan?.patient || null,
    plan_meta: planObj.plan_meta || planObj.plan?.plan_meta || null,
    targets,
    meal_context: mealSection || null,
    extras: planObj.extras || planObj.plan?.extras || null,
    constraints: planObj.constraints || planObj.plan?.constraints || null,
    recommendations: planObj.recommendations || planObj.plan?.recommendations || [],
    warnings: planObj.warnings || planObj.plan?.warnings || []
  };
}

return items.map((item) => {
  const input = item.json || {};
  const warnings = [];

  const phone = normalizeText(input.phone);
  const patient_dni = normalizeText(input.patient_dni);
  const patient_key = patient_dni || phone || null;

  const user_text = normalizeText(input.user_text);
  const label_text = normalizeText(input.label_text);

  const imageAnalysis = safeParseJson(input.image_analysis_json, null);
  if (input.image_analysis_json && !imageAnalysis) {
    warnings.push("image_analysis_json no es JSON vÃ¡lido (se ignorarÃ¡).");
  }

  const planSource =
    input.plan_json ??
    input.plan_obj ??
    input.plan_json_raw ??
    input.nutrition_plan ??
    input.current_plan ??
    input.plan ??
    null;

  const parsed = safeParseJson(planSource, null);
  let planObj = parsed ? unwrapPlanObject(parsed, warnings) : null;

  if (typeof planObj === "string") {
    const reparsed = safeParseJson(planObj, null);
    planObj = reparsed ? unwrapPlanObject(reparsed, warnings) : null;
  }

  if (!planObj || typeof planObj !== "object") {
    if (planSource) {
      const s = typeof planSource === "string" ? sanitizeBase(planSource) : "";
      warnings.push(
        `plan_json existe pero no se pudo normalizar/parsear. ` +
        (s ? `prefix='${s.slice(0, 20)}' len=${s.length}` : "")
      );
    }
    planObj = null;
  }

  const plan_status = planObj ? computePlanStatus(planObj) : null;

  let detected_meal = "unknown";
  if (input.meal_hint && input.meal_hint !== "auto") detected_meal = input.meal_hint;
  else detected_meal = detectMealFromText(user_text);

  const mealSection = planObj ? pickMealSection(planObj, detected_meal) : null;
  if (planObj && !mealSection) {
    warnings.push(`No se encontrÃ³ secciÃ³n del plan para meal='${detected_meal}'. Se enviarÃ¡ el plan general.`);
  }

  const plan_context_obj = planObj ? buildPlanContext(planObj, mealSection, plan_status) : null;

  let plan_context_json = "";
  if (plan_context_obj) {
    try { plan_context_json = JSON.stringify(plan_context_obj); }
    catch (_) { warnings.push("No se pudo stringify plan_context_obj."); plan_context_json = ""; }
  }

  return {
    json: {
      phone,
      patient_dni,
      patient_key,
      context_date: input.context_date || null,
      timezone: input.timezone || null,
      conversation_id: input.conversation_id || null,
      message_id: input.message_id || null,
      attachments_count: Number.isFinite(input.attachments_count)
        ? input.attachments_count
        : (input.attachments_count != null ? Number(input.attachments_count) : null),

      user_text_norm: user_text,
      label_text_norm: label_text,
      image_analysis: imageAnalysis,

      plan_obj: planObj,
      plan_status,
      detected_meal,

      plan_context_json,
      // si no querÃ©s debug, podÃ©s borrar estas 2:
      plan_context_obj,
      warnings
    }
  };
});

