// n8n Code node (JavaScript)
// POST "clasify" LLM: normaliza salida para:
// - Gatear si corre ai_analysis (decision)
// - Exponer campos individuales (status/mensaje/preguntas/flags/...)
// - Mantener passthrough (user_text_norm, image_analysis, plan_context_json, etc.)
// Robustez 99.9%: soporta mÃºltiples rutas de output + JSON embebido + backticks.

function normalizeNewlines(s) {
  return (s ?? "").toString().replace(/\r\n/g, "\n").replace(/\r/g, "\n");
}

function stripDiacritics(s) {
  return (s ?? "")
    .toString()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function toSnakeKey(s) {
  return stripDiacritics(s)
    .toUpperCase()
    .trim()
    .replace(/[()]/g, "")
    .replace(/[^\w\s-]/g, "")
    .replace(/[\s-]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function sanitize(s) {
  return (s ?? "").toString().replace(/\u0000/g, "").trim();
}

// --- extracciÃ³n robusta de texto LLM ---
function extractLLMText(input) {
  const candidates = [
    input?.output?.[0]?.content?.[0]?.text,
    input?.output?.[0]?.content?.[0]?.output_text?.text,
    input?.output?.[0]?.text,
    input?.content?.[0]?.text,
    input?.text,
    input?.message,
    input?.data?.[0]?.text,
    input?.choices?.[0]?.message?.content,
  ];

  for (const c of candidates) {
    if (typeof c === "string" && c.trim()) return c;
  }

  // Si viene como array de outputs (variante)
  if (Array.isArray(input?.output)) {
    for (const out of input.output) {
      const t = out?.content?.[0]?.text ?? out?.text;
      if (typeof t === "string" && t.trim()) return t;
    }
  }

  return "";
}

// --- extrae primer JSON substring por balanceo { } o [ ] ---
function extractFirstJsonSubstring(raw) {
  const s = sanitize(raw);
  if (!s) return null;

  const starts = [];
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (c === "{" || c === "[") starts.push(i);
  }
  if (!starts.length) return null;

  const tryFrom = (startIdx) => {
    const open = s[startIdx];
    const close = open === "{" ? "}" : "]";
    let depth = 0;
    let inStr = false;
    let esc = false;

    for (let i = startIdx; i < s.length; i++) {
      const ch = s[i];

      if (inStr) {
        if (esc) esc = false;
        else if (ch === "\\") esc = true;
        else if (ch === "\"") inStr = false;
        continue;
      }

      if (ch === "\"") {
        inStr = true;
        continue;
      }

      if (ch === open) depth++;
      if (ch === close) depth--;

      if (depth === 0) return s.slice(startIdx, i + 1).trim();
    }
    return null;
  };

  for (const idx of starts) {
    const candidate = tryFrom(idx);
    if (!candidate) continue;
    if (
      (candidate.startsWith("{") && candidate.endsWith("}")) ||
      (candidate.startsWith("[") && candidate.endsWith("]"))
    ) {
      return candidate;
    }
  }
  return null;
}

// --- quita fences ```json ...``` ---
function stripCodeFences(raw) {
  let s = sanitize(raw);
  if (!s) return s;

  // ```json\n{...}\n```
  const fence = s.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/i);
  if (fence) return fence[1].trim();

  // si hay fences mezclados en medio, lo dejamos y luego usamos extractor
  return s;
}

// --- detecta JSON "escapado" sin comillas externas: {\"a\":\"b\"} ---
function looksLikeEscapedJson(raw) {
  const s = sanitize(raw);
  if (!s) return false;
  return /\\\"[A-Za-z0-9_\-\s]+\\\"\s*:/.test(s);
}

function unescapeJsonLike(raw) {
  let s = sanitize(raw);
  if (!s) return s;

  s = s
    .replace(/\\\"/g, "\"")
    .replace(/\\n/g, "\n")
    .replace(/\\r/g, "\r")
    .replace(/\\t/g, "\t")
    .replace(/\\\//g, "/");

  // colapsa \\ -> \
  s = s.replace(/\\\\/g, "\\");

  return s.trim();
}

// --- parse JSON best-effort ---
function safeParseJsonBestEffort(maybe, fallback = null) {
  if (maybe == null) return fallback;
  if (typeof maybe === "object") return maybe;
  if (typeof maybe !== "string") return fallback;

  let raw = stripCodeFences(maybe);
  raw = sanitize(raw);
  if (!raw) return fallback;

  // 1) parse directo
  try {
    const v = JSON.parse(raw);
    return v;
  } catch (_) {}

  // 2) si parece escapado, unescape y parse
  if (looksLikeEscapedJson(raw)) {
    try {
      return JSON.parse(unescapeJsonLike(raw));
    } catch (_) {}
  }

  // 3) extraer JSON embebido y parsear
  const embedded = extractFirstJsonSubstring(raw);
  if (embedded) {
    try {
      return JSON.parse(embedded);
    } catch (_) {}
    if (looksLikeEscapedJson(embedded)) {
      try {
        return JSON.parse(unescapeJsonLike(embedded));
      } catch (_) {}
    }
  }

  return fallback;
}

// --- normaliza food_type (incluye typos como "PACKGED") ---
function normalizeFoodType(ft) {
  const s = (ft ?? "").toString().trim().toUpperCase();

  if (!s) return null;
  if (/(PACK|PACKA|PACKG|PACKGE|PACKGED|PACKAGED)/.test(s)) return "PACKAGED";
  if (/(HOME|MEAL|PLATE|COMIDA|CASER|PLATO|RECETA)/.test(s)) return "MEAL";
  if (/(RESTA|DELIV|FAST|STREET)/.test(s)) return "MEAL"; // suele ser comida â€œno envasadaâ€
  return s; // fallback
}

// --- parsea response_text con headers tipo "ROMMY_STATUS:" (y tambiÃ©n soporta numerado) ---
function splitSectionsFlexible(text) {
  const t = normalizeNewlines(text).trim();
  if (!t) return { sections: {}, raw: "" };

  // 1) si viene numerado: "1) ROMMY_STATUS:"
  const numRe = /(?:^|\n)\s*\d+\)\s*([^\n:]+?)\s*:\s*\n/g;
  let m;
  let numMatches = [];
  while ((m = numRe.exec(t)) !== null) {
    numMatches.push({ idx: m.index, end: numRe.lastIndex, title: m[1].trim() });
  }
  if (numMatches.length) {
    const out = {};
    for (let i = 0; i < numMatches.length; i++) {
      const cur = numMatches[i];
      const next = numMatches[i + 1];
      const body = t.slice(cur.end, next ? next.idx : t.length).trim();
      out[toSnakeKey(cur.title)] = body;
    }
    return { sections: out, raw: t };
  }

  // 2) headers en mayÃºsculas: "ROMMY_STATUS:\n..."
  const hdrRe = /(?:^|\n)\s*([A-ZÃÃ‰ÃÃ“ÃšÃ‘][A-ZÃÃ‰ÃÃ“ÃšÃ‘0-9_ \-]{2,})\s*:\s*\n/g;
  let hdrMatches = [];
  while ((m = hdrRe.exec(t)) !== null) {
    hdrMatches.push({ idx: m.index, end: hdrRe.lastIndex, title: m[1].trim() });
  }

  if (!hdrMatches.length) return { sections: { RAW: t }, raw: t };

  const out = {};
  for (let i = 0; i < hdrMatches.length; i++) {
    const cur = hdrMatches[i];
    const next = hdrMatches[i + 1];
    const body = t.slice(cur.end, next ? next.idx : t.length).trim();
    out[toSnakeKey(cur.title)] = body;
  }
  return { sections: out, raw: t };
}

function firstNonEmptyLine(body) {
  const lines = normalizeNewlines(body).split("\n").map((l) => l.trim()).filter(Boolean);
  return lines[0] ?? "";
}

function parseQuestions(body) {
  const lines = normalizeNewlines(body).split("\n").map((l) => l.trim()).filter(Boolean);
  const out = [];
  for (const line of lines) {
    const q = line
      .replace(/^\-\s*/, "")
      .replace(/^\d+\)\s*/, "")
      .trim();
    if (q) out.push(q);
  }
  return out;
}

function parseFlags(body) {
  const s = sanitize(body);
  if (!s) return [];
  // puede venir "A; B; C" o "A, B" o lÃ­neas
  const tokens = s
    .split(/[\n;,]+/g)
    .map((x) => x.trim())
    .filter(Boolean)
    .map((x) => stripDiacritics(x).toUpperCase().replace(/\s+/g, "_"));
  // unique
  return Array.from(new Set(tokens));
}

function parseDatosTracker(body) {
  const s = sanitize(body);
  if (!s) return { estimable: false, missing: "sin datos", kcal: null, protein_g: null, carbs_g: null, fat_g: null, confidence: null };

  // Caso: "No estimable â€” falta: ..."
  if (/no\s*estimable/i.test(s)) {
    const missing = s.split(/falta\s*:\s*/i)[1]?.trim() ?? s;
    return { estimable: false, missing, kcal: null, protein_g: null, carbs_g: null, fat_g: null, confidence: null };
  }

  // Caso: pipe style o texto con nÃºmeros
  const num = (re) => {
    const m = s.match(re);
    if (!m) return null;
    const n = Number((m[1] ?? "").replace(",", "."));
    return Number.isFinite(n) ? n : null;
  };

  const kcal = num(/kcal\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i);
  const protein = num(/prote(ina|Ã­nas)?\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i) ?? num(/protein(?:_g)?\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i);
  const carbs = num(/carb(?:ohidratos)?\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i) ?? num(/carbs(?:_g)?\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i);
  const fat = num(/grasas?\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i) ?? num(/fat(?:_g)?\s*:\s*([0-9]+(?:[.,][0-9]+)?)/i);
  const conf = num(/confianza\s*:\s*(0?\.\d+|1(?:\.0+)?)/i);

  const estimable = [kcal, protein, carbs, fat].some((x) => x != null);

  return { estimable, missing: estimable ? null : "faltan macros", kcal, protein_g: protein, carbs_g: carbs, fat_g: fat, confidence: conf };
}

function normalizeDecision(decision) {
  const s = (decision ?? "").toString().trim().toUpperCase();
  if (!s) return null;
  if (s.includes("STOP")) return "STOP_AND_REPLY";
  if (s.includes("PROCEED") || s.includes("RUN") || s.includes("ANALYSIS")) return "PROCEED_TO_ANALYSIS";
  return s;
}

return items.map((item) => {
  const input = item.json || {};

  const llmText = extractLLMText(input);
  const parsed = safeParseJsonBestEffort(llmText, null);

  // Si el nodo ya viene entregando JSON directo (rarÃ­simo pero posible)
  const classifyObj = parsed && typeof parsed === "object" ? parsed : (input.decision ? input : null);

  const out = {
    success: false,

    // Gate principal
    decision: null,
    decision_norm: null,
    stop_reason_code: null,

    // Texto para responder (si STOP)
    response_text_raw: "",
    // Secciones parseadas
    rommy_status: { estado: null, motivo_breve: null },
    mensaje_listo_para_paciente: "",
    resumen_para_rommy_text: "",
    datos_para_tracker: { estimable: false, missing: null, kcal: null, protein_g: null, carbs_g: null, fat_g: null, confidence: null },
    accion_recomendada: null,
    preguntas_pendientes: [],
    flags_list: [],

    // Campos de clasificaciÃ³n / bÃºsqueda
    packaged_product: null,
    packaged_needs_label: null,
    packaged_needs_grams: null,
    packaged_clarifying_questions: [],
    food_type: null,
    food_type_norm: null,
    search_terms: { ingredients: [], dish_name: null, brand: null, variants: [] },

    // Passthrough para ai_analysis
    phone: input.phone ?? "",
    patient_dni: input.patient_dni ?? "",
    patient_key: input.patient_key ?? null,
    context_date: input.context_date ?? null,
    timezone: input.timezone ?? null,
    conversation_id: input.conversation_id ?? null,
    message_id: input.message_id ?? null,
    attachments_count: input.attachments_count ?? null,

    user_text_norm: input.user_text_norm ?? input.user_text ?? "",
    label_text_norm: input.label_text_norm ?? input.label_text ?? "",
    image_analysis: input.image_analysis ?? input.image_analysis_json ?? null,

    plan_status: input.plan_status ?? null,
    detected_meal: input.detected_meal ?? input.meal_hint ?? null,
    plan_context_json: input.plan_context_json ?? "",

    // Usabilidad / debug
    should_run_ai_analysis: false,
    final_reply_text: "",
    warnings: [],
    error: null,
    raw_llm_text: llmText || "",
    raw_llm_json: classifyObj || null,
  };

  if (!classifyObj) {
    out.error = { code: "CLASSIFY_PARSE_FAILED", message: "No se pudo parsear JSON desde el output del LLM (clasify)." };
    out.decision_norm = "STOP_AND_REPLY";
    out.stop_reason_code = "CLASSIFY_OUTPUT_INVALID";
    out.rommy_status.estado = "ESCALATE";
    out.mensaje_listo_para_paciente = "Tuve un problema tÃ©cnico interpretando la informaciÃ³n. Â¿PodÃ©s reenviar la foto y el texto, por favor?";
    out.final_reply_text = out.mensaje_listo_para_paciente;
    return { json: out };
  }

  // ---- mapear campos base desde JSON del LLM ----
  out.decision = classifyObj.decision ?? null;
  out.decision_norm = normalizeDecision(out.decision);
  out.stop_reason_code = classifyObj.stop_reason_code ?? null;

  out.response_text_raw = classifyObj.response_text ?? "";
  out.phone = classifyObj.phone || out.phone;
  out.patient_dni = classifyObj.patient_dni || out.patient_dni;
  out.patient_key = classifyObj.patient_key || out.patient_key;
  out.context_date = classifyObj.context_date ?? out.context_date;
  out.timezone = classifyObj.timezone ?? out.timezone;
  out.conversation_id = classifyObj.conversation_id ?? out.conversation_id;
  out.message_id = classifyObj.message_id ?? out.message_id;
  out.attachments_count = classifyObj.attachments_count ?? out.attachments_count;

  out.user_text_norm = classifyObj.user_text_norm ?? out.user_text_norm;
  out.label_text_norm = classifyObj.label_text_norm ?? out.label_text_norm;
  out.image_analysis = classifyObj.image_analysis ?? out.image_analysis;
  out.plan_status = classifyObj.plan_status ?? out.plan_status;
  out.detected_meal = classifyObj.detected_meal ?? out.detected_meal;
  out.plan_context_json = classifyObj.plan_context_json ?? out.plan_context_json;

  out.packaged_product = classifyObj.packaged_product ?? null;
  out.packaged_needs_label = classifyObj.packaged_needs_label ?? null;
  out.packaged_needs_grams = classifyObj.packaged_needs_grams ?? null;
  out.packaged_clarifying_questions = Array.isArray(classifyObj.packaged_clarifying_questions)
    ? classifyObj.packaged_clarifying_questions
    : [];

  out.food_type = classifyObj.food_type ?? null;
  out.food_type_norm = normalizeFoodType(out.food_type);

  if (classifyObj.search_terms && typeof classifyObj.search_terms === "object") {
    out.search_terms = {
      ingredients: Array.isArray(classifyObj.search_terms.ingredients) ? classifyObj.search_terms.ingredients : [],
      dish_name: classifyObj.search_terms.dish_name ?? null,
      brand: classifyObj.search_terms.brand ?? null,
      variants: Array.isArray(classifyObj.search_terms.variants) ? classifyObj.search_terms.variants : [],
    };
  }

  // warnings del LLM
  if (Array.isArray(classifyObj.warnings)) out.warnings.push(...classifyObj.warnings);

  // ---- parsear response_text en secciones ----
  if (out.response_text_raw && typeof out.response_text_raw === "string") {
    const { sections } = splitSectionsFlexible(out.response_text_raw);

    // aliases por si vienen con keys distintas
    const get = (...keys) => {
      for (const k of keys) {
        const kk = toSnakeKey(k);
        if (sections[kk]) return sections[kk];
      }
      return "";
    };

    const rommyStatusBody = get("ROMMY_STATUS");
    const msgBody = get("MENSAJE_LISTO_PARA_PACIENTE");
    const resumenBody = get("RESUMEN_PARA_ROMMY", "RESUMEN_PARA_ROMMY_INTERNO_CORTO");
    const trackerBody = get("DATOS_PARA_TRACKER", "DATOS_PARA_TRACKER_SI_APLICA");
    const accionBody = get("ACCION_RECOMENDADA", "ACCION_RECOMENDADA_PARA_EL_WORKFLOW");
    const preguntasBody = get("PREGUNTAS_PENDIENTES", "PREGUNTAS_PENDIENTES_SI_APLICA");
    const flagsBody = get("FLAGS");

    // ROMMY_STATUS suele ser 1 lÃ­nea (NEEDS_CLARIFICATION / OK / ERROR)
    const estado = firstNonEmptyLine(rommyStatusBody);
    out.rommy_status.estado = estado || null;

    out.mensaje_listo_para_paciente = sanitize(msgBody);
    out.resumen_para_rommy_text = sanitize(resumenBody);
    out.datos_para_tracker = parseDatosTracker(trackerBody);

    const accionLine = firstNonEmptyLine(accionBody);
    out.accion_recomendada = accionLine ? accionLine.trim() : null;

    out.preguntas_pendientes = parseQuestions(preguntasBody);

    out.flags_list = parseFlags(flagsBody);

    // Si el LLM no completÃ³ bien flags booleanos, los derivamos
    const flagsSet = new Set(out.flags_list);
    if (out.packaged_product == null) out.packaged_product = flagsSet.has("PACKAGED_PRODUCT");
    if (out.packaged_needs_label == null) out.packaged_needs_label = flagsSet.has("NEED_LABEL") || flagsSet.has("NEEDS_LABEL");
    if (out.packaged_needs_grams == null) out.packaged_needs_grams = flagsSet.has("NEED_GRAMS") || flagsSet.has("NEEDS_GRAMS");

    // Si decision estÃ¡ vacÃ­a pero ROMMY_STATUS sugiere stop
    if (!out.decision_norm) {
      if (out.rommy_status.estado && out.rommy_status.estado.toUpperCase().includes("NEEDS")) {
        out.decision_norm = "STOP_AND_REPLY";
      }
    }
  }

  // ---- decision final (fallbacks) ----
  if (!out.decision_norm) out.decision_norm = normalizeDecision(out.decision) || "STOP_AND_REPLY";

  out.should_run_ai_analysis = out.decision_norm === "PROCEED_TO_ANALYSIS";

  // reply text
  if (out.decision_norm === "STOP_AND_REPLY") {
    out.final_reply_text =
      out.mensaje_listo_para_paciente ||
      "Necesito un dato adicional para poder analizar correctamente. Â¿PodÃ©s ampliar la info?";
  } else {
    out.final_reply_text = ""; // no respondemos acÃ¡; sigue ai_analysis
  }

  // success mÃ­nimo
  out.success = true;

  // sanity extra: ingredients siempre array
  if (!Array.isArray(out.search_terms.ingredients)) out.search_terms.ingredients = [];

  // compat: si food_type_norm quedÃ³ null, usar raw
  if (!out.food_type_norm) out.food_type_norm = out.food_type ? String(out.food_type).toUpperCase() : null;

  return { json: out };
});
